/* =====================================================================
 * INJECTION LOGIC
 * ===================================================================== */

const SLUGS = Object.keys(NEW_EXTRAS);

const DICT_MAP = [
  { label: "CITY_GARAGE_EXTRAS",  regex: /const\s+CITY_GARAGE_EXTRAS\s*=\s*\{/,  data: NEW_EXTRAS  },
  { label: "CITY_GARAGE_DEEP",    regex: /const\s+CITY_GARAGE_DEEP\s*=\s*\{/,    data: NEW_DEEP    },
  { label: "CITY_GARAGE_EXTRAS2", regex: /const\s+CITY_GARAGE_EXTRAS2\s*=\s*\{/, data: NEW_EXTRAS2 },
  { label: "CITY_GARAGE_EXTRA3",  regex: /const\s+CITY_GARAGE_EXTRA3\s*=\s*\{/,  data: NEW_EXTRA3  },
  { label: "CITY_GARAGE_EXTRA4",  regex: /const\s+CITY_GARAGE_EXTRA4\s*=\s*\{/,  data: NEW_EXTRA4  },
];

let src = fs.readFileSync(TARGET, "utf8");
let changeCount = 0;

for (const { label, regex, data } of DICT_MAP) {
  // Find the dict opening
  const openMatch = regex.exec(src);
  if (!openMatch) {
    console.error(`ERROR: could not find ${label} in source`);
    process.exit(1);
  }

  // Find the matching closing `};` by brace counting from the opening
  let braceDepth = 0;
  let closeIdx = -1;
  let inString = false;
  let stringChar = "";
  let escaped = false;
  for (let i = openMatch.index; i < src.length; i++) {
    const ch = src[i];
    if (escaped) { escaped = false; continue; }
    if (ch === "\\") { escaped = true; continue; }
    if (inString) {
      if (ch === stringChar) inString = false;
      continue;
    }
    if (ch === '"' || ch === "'" || ch === "`") { inString = true; stringChar = ch; continue; }
    if (ch === "{") braceDepth++;
    if (ch === "}") {
      braceDepth--;
      if (braceDepth === 0) { closeIdx = i; break; }
    }
  }
  if (closeIdx === -1) {
    console.error(`ERROR: could not find closing brace for ${label}`);
    process.exit(1);
  }

  // Check which slugs are already present
  const dictBody = src.slice(openMatch.index, closeIdx);
  const toInsert = [];
  for (const slug of SLUGS) {
    if (dictBody.includes(`"${slug}"`)) {
      console.log(`  SKIP ${label} / ${slug} (already present)`);
      continue;
    }
    toInsert.push(slug);
  }
  if (toInsert.length === 0) {
    console.log(`${label}: all metros already present, skipping`);
    continue;
  }

  // Build insertion text
  let insertion = "";
  for (const slug of toInsert) {
    const entry = data[slug];
    if (typeof entry === "string") {
      // DEEP dict is flat string values
      insertion += `  "${slug}": ${JSON.stringify(entry)},\n`;
    } else {
      // Object entries
      const lines = [];
      lines.push(`  "${slug}": {`);
      const keys = Object.keys(entry);
      for (const key of keys) {
        const val = entry[key];
        // Use template literals for multi-line
        lines.push(`    ${key}: \`${val.replace(/`/g, "\\`")}\`,`);
      }
      lines.push(`  },`);
      insertion += lines.join("\n") + "\n";
    }
  }

  // Insert before the closing `}`
  src = src.slice(0, closeIdx) + insertion + src.slice(closeIdx);
  changeCount += toInsert.length;
  console.log(`${label}: inserted ${toInsert.length} metros`);
}

if (changeCount === 0) {
  console.log("No changes needed -- all metros already present in all dicts.");
} else {
  fs.writeFileSync(TARGET, src, "utf8");
  console.log(`\nDone. Wrote ${changeCount} total insertions across 5 dicts to:\n  ${TARGET}`);
}
